remediationScripts.terraform:
resource "azurerm_storage_account" "optimized" {
  name                     = "stgarchivedata01"
  resource_group_name      = "rg-prod"
  location                 = "westeurope"
  account_tier             = "Standard"
  account_replication_type = "LRS"

  tags = {
    Environment = "production"
    CostCenter  = "engineering"
    OptimizedBy = "AuraSentry"
  }
}

remediationScripts.bicep:
resource sa 'Microsoft.Storage/storageAccounts@2023-04-01' = {
  name: 'stgarchivedata01'
  location: 'westeurope'
  sku: {
    name: 'Standard_LRS'
  }
  kind: 'StorageV2'
}

remediationScripts.terraform:
resource "azurerm_linux_virtual_machine" "dev_vm" {
  name                = "dev-app-worker-04"
  resource_group_name = "rg-dev"
  location            = "northeurope"
  size                = "Standard_D2s_v3"

  admin_username = "azureuser"
  network_interface_ids = [azurerm_network_interface.dev_nic.id]

  os_disk {
    caching              = "ReadWrite"
    storage_account_type = "Standard_LRS"
  }

  tags = {
    Environment = "dev"
    OptimizedBy = "AuraSentry"
  }
}

remediationScripts.bicep:
resource vm 'Microsoft.Compute/virtualMachines@2023-09-01' = {
  name: 'dev-app-worker-04'
  location: 'northeurope'
  properties: {
    hardwareProfile: {
      vmSize: 'Standard_D2s_v3'
    }
    storageProfile: {
      osDisk: {
        createOption: 'FromImage'
        managedDisk: {
          storageAccountType: 'Standard_LRS'
        }
      }
    }
  }
}

remediationScripts.terraform:
resource "azurerm_mssql_database" "db" {
  name      = "sqldb-finance-reporting"
  server_id = azurerm_mssql_server.server.id
  sku_name  = "S3"

  tags = {
    OptimizedBy = "AuraSentry"
  }
}

resource "azurerm_linux_virtual_machine" "oracle_vm" {
  name                = "prod-oracle-erp-db"
  resource_group_name = "rg-prod"
  location            = "japaneast"
  size                = "Standard_E4s_v3"

  tags = {
    Environment = "production"
    OptimizedBy = "AuraSentry"
  }
}
